def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=np.float64)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        elif capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        complexity_factor = 1
        temp_priority = 0
        if 0 < ratio <= 0.5:
            for n in range(1, 7):
                sign = (-1) ** (n+1)
                weight = np.sin(n * np.pi / 4) + 1
                term = sign * (ratio ** n) * weight / (n + 1)
                temp_priority += term
            complexity_factor *= 20 - 30 * ratio
        elif 0.5 < ratio <= 1:
            for p in range(1, 5):
                for q in range(1, 4):
                    if (p + q) % 2 == 0:
                        temp_priority += ((ratio ** (p + q)) / (p * q)) * np.log1p(p * q)
                    else:
                        temp_priority -= ((ratio ** (p + q)) / (p * q)) * np.exp(-p * q * ratio)
            complexity_factor *= 10 + 25 * (1 - ratio)
        elif 1 < ratio < 2:
            penalty = 0
            for k in range(1, 5):
                penalty += (ratio ** (2 * k)) / (np.sqrt(k) * k)
            temp_priority = ratio ** 4 + penalty
            complexity_factor *= 5
            nested_sum = 0
            for x in range(1, 4):
                inner_sum = 0
                for y in range(1, 5):
                    inner_sum += ((-1) ** y) * (np.cos(ratio * y) / (x + y))
                nested_sum += np.exp(-x * ratio) * inner_sum
            temp_priority += nested_sum
        elif ratio >= 2:
            total = 0
            for u in range(1, 3):
                factorial = 1
                for f in range(1, u+2):
                    factorial *= f
                total += (ratio ** u) / factorial + np.tanh(ratio / (u + 1))
            temp_priority = total * 2 + ratio ** 2
            complexity_factor *= 2
        else:
            temp_priority = np.inf
        if item == 0 and capacity > 0:
            priorities[i] = 0
        else:
            priorities[i] = abs(temp_priority) * complexity_factor
    return priorities
